challenges.solution:
h1 { font-size: clamp(2rem, 1rem + 4vw, 4rem); line-height: 1.1; }
h2 { font-size: clamp(1.5rem, 1rem + 3vw, 3rem); line-height: 1.15; }
h3 { font-size: clamp(1.25rem, 0.8rem + 2vw, 2.5rem); line-height: 1.2; }
h4 { font-size: clamp(1.125rem, 0.7rem + 1.5vw, 2rem); line-height: 1.25; }
h5 { font-size: clamp(1rem, 0.6rem + 1.2vw, 1.5rem); line-height: 1.3; }
h6 { font-size: clamp(0.875rem, 0.5rem + 1vw, 1.25rem); line-height: 1.35; }

:root { --rhythm: calc(1rem * 1.5); }
h1 { margin-bottom: var(--rhythm); }
p { margin-bottom: var(--rhythm); }
h2 { margin-top: calc(var(--rhythm) * 2); margin-bottom: var(--rhythm); }
blockquote { margin: var(--rhythm) 0; padding-left: var(--rhythm); }
